external_knowledge:
- 'vibrant ad campaigns' refer to the active campaigns;
- 'significant amount of attention' implies a high number of likes, at least 100;
- 'funding levels' is a vague term for the budget allocated for the campaigns.

sql:
SELECT campaign_name, budget
FROM ad_campaigns
WHERE objective = 'Increase revenue' AND campaign_status = 'Active';

SELECT SUM(budget) 
FROM ad_campaigns
WHERE start_date BETWEEN '2023-01-01' AND '2023-12-31';

SELECT campaign_id, AVG(impressions) AS average_impression_rate
FROM ad_performance
GROUP BY campaign_id;

